#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MOD 1000000007
#define MAX_N 205

// Structure to represent a road
typedef struct {
    int u, v, time;
} Road;

// Structure to represent a node in the priority queue
typedef struct {
    long long dist;
    int u;
} Node;

// Comparison function for the priority queue
int compare(const void *a, const void *b) {
    Node *node1 = (Node *)a;
    Node *node2 = (Node *)b;
    return (node1->dist > node2->dist);
}

// Function to find the number of distinct shortest paths
int countShortestPaths(int n, Road *roads, int m) {
    // Create an adjacency list representation of the graph
    int **adj = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        adj[i] = (int *)malloc(2 * m * sizeof(int));
    }
    int *head = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        head[i] = -1;
    }
    for (int i = 0; i < m; i++) {
        int u = roads[i].u;
        int v = roads[i].v;
        int time = roads[i].time;
        adj[u][++head[u] * 2] = v;
        adj[u][++head[u] * 2 + 1] = time;
        adj[v][++head[v] * 2] = u;
        adj[v][++head[v] * 2 + 1] = time;
    }

    // Create a priority queue to store nodes to be processed
    Node *pq = (Node *)malloc(n * sizeof(Node));
    int pq_size = 0;

    // Create arrays to store the distance and number of ways to reach each intersection
    long long *dist = (long long *)malloc(n * sizeof(long long));
    int *ways = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        dist[i] = LLONG_MAX;
        ways[i] = 0;
    }
    dist[0] = 0;
    ways[0] = 1;
    pq[pq_size].dist = 0;
    pq[pq_size].u = 0;
    pq_size++;

    // Process nodes in the priority queue
    while (pq_size > 0) {
        int u = pq[0].u;
        long long d = pq[0].dist;
        pq_size--;
        for (int i = 1; i < pq_size; i++) {
            pq[i - 1] = pq[i];
        }
        if (d > dist[u]) continue;
        for (int i = head[u]; i != -1; i += 2) {
            int v = adj[u][i];
            int time = adj[u][i + 1];
            long long nd = d + time;
            if (nd < dist[v]) {
                dist[v] = nd;
                ways[v] = ways[u];
                pq[pq_size].dist = nd;
                pq[pq_size].u = v;
                pq_size++;
            } else if (nd == dist[v]) {
                ways[v] = (ways[v] + ways[u]) % MOD;
            }
        }
    }

    // Return the number of distinct shortest paths to the last intersection
    return ways[n - 1];
}

int main() {
    int T;
    scanf("%d", &T);
    while (T-- > 0) {
        int n;
        scanf("%d", &n);
        int m;
        scanf("%d", &m);
        Road *roads = (Road *)malloc(m * sizeof(Road));
        for (int i = 0; i < m; i++) {
            scanf("%d %d %d", &roads[i].u, &roads[i].v, &roads[i].time);
        }
        printf("%d\n", countShortestPaths(n, roads, m));
    }
    return 0;
}

