struct Node {
    long long dist;
    int u;
};

// Comparison function for the priority queue
struct compare {
    bool operator()(const Node &a, const Node &b) {
        return a.dist > b.dist;
    }
};

// Function to find the number of distinct shortest paths
int countShortestPaths(int n, vector<Road> &roads) {
    // Create an adjacency list representation of the graph
    vector<vector<pair<int, int>>> adj(n);
    for (int i = 0; i < roads.size(); i++) {
        int u = roads[i].u;
        int v = roads[i].v;
        int time = roads[i].time;
        adj[u].push_back({v, time});
        adj[v].push_back({u, time});
    }

    // Create a priority queue to store nodes to be processed
    priority_queue<Node, vector<Node>, compare> pq;

    // Create arrays to store the distance and number of ways to reach each intersection
    vector<long long> dist(n, LLONG_MAX);
    vector<int> ways(n, 0);
    dist[0] = 0;
    ways[0] = 1;
    pq.push({0, 0});

    // Process nodes in the priority queue
    while (!pq.empty()) {
        int u = pq.top().u;
        long long d = pq.top().dist;
        pq.pop();
        if (d > dist[u]) continue;
        for (int i = 0; i < adj[u].size(); i++) {
            int v = adj[u][i].first;
            int time = adj[u][i].second;
            long long nd = d + time;
            if (nd < dist[v]) {
                dist[v] = nd;
                ways[v] = ways[u];
                pq.push({nd, v});
            } else if (nd == dist[v]) {
                ways[v] = (ways[v] + ways[u]) % MOD;
            }
        }
    }

    // Return the number of distinct shortest paths to the last intersection
    return ways[n - 1];
}

