import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.PrintWriter;
import java.util.ArrayList;
import java.util.List;
import java.util.PriorityQueue;
import java.util.StringTokenizer;

public class Main {
    static final int MOD = 1000000007;

    // Structure to represent a road
    static class Road {
        int u, v, time;
        Road(int u, int v, int time) {
            this.u = u;
            this.v = v;
            this.time = time;
        }
    }

    // Structure to represent a node in the priority queue
    static class Node implements Comparable<Node> {
        long dist;
        int u;
        Node(long dist, int u) {
            this.dist = dist;
            this.u = u;
        }
        @Override
        public int compareTo(Node other) {
            return Long.compare(this.dist, other.dist);
        }
    }

    // Function to find the number of distinct shortest paths
    public static int countShortestPaths(int n, List<Road> roads) {
        // Create an adjacency list representation of the graph
        List<List<int[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (Road road : roads) {
            adj.get(road.u).add(new int[] {road.v, road.time});
            adj.get(road.v).add(new int[] {road.u, road.time});
        }

        // Create a priority queue to store nodes to be processed
        PriorityQueue<Node> pq = new PriorityQueue<>();

        // Create arrays to store the distance and number of ways to reach each intersection
        long[] dist = new long[n];
        int[] ways = new int[n];
        for (int i = 0; i < n; i++) {
            dist[i] = Long.MAX_VALUE;
            ways[i] = 0;
        }
        dist[0] = 0;
        ways[0] = 1;
        pq.offer(new Node(0, 0));

        // Process nodes in the priority queue
        while (!pq.isEmpty()) {
            Node node = pq.poll();
            int u = node.u;
            long d = node.dist;
            if (d > dist[u]) continue;
            for (int[] edge : adj.get(u)) {
                int v = edge[0];
                int time = edge[1];
                long nd = d + time;
                if (nd < dist[v]) {
                    dist[v] = nd;
                    ways[v] = ways[u];
                    pq.offer(new Node(nd, v));
                } else if (nd == dist[v]) {
                    ways[v] = (ways[v] + ways[u]) % MOD;
                }
            }
        }

        // Return the number of distinct shortest paths to the last intersection
        return ways[n - 1];
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        PrintWriter pw = new PrintWriter(System.out);
        int T = Integer.parseInt(br.readLine());
        while (T-- > 0) {
            int n = Integer.parseInt(br.readLine());
            List<Road> roads = new ArrayList<>();
            int m = Integer.parseInt(br.readLine());
            for (int i = 0; i < m; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken());
                int v = Integer.parseInt(st.nextToken());
                int time = Integer.parseInt(st.nextToken());
                roads.add(new Road(u, v, time));
            }
            pw.println(countShortestPaths(n, roads));
        }
        pw.close();
    }
}

